def set_font(run, size=14, bold=False):
    run.bold = bold
    font = run.font
    font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    font.size = Pt(size)


def add_paragraph(doc, text, preview, center=False, bold=False, indent=True):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER if center else WD_ALIGN_PARAGRAPH.JUSTIFY
    p.paragraph_format.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE
    p.paragraph_format.space_before = Pt(0)
    p.paragraph_format.space_after = Pt(0)
    if indent:
        p.paragraph_format.first_line_indent = Cm(1.25)
    run = p.add_run(text)
    set_font(run, 14, bold)
    preview.append(text)
    return p


def add_heading(doc, text, preview):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.LEFT
    p.paragraph_format.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE
    p.paragraph_format.space_before = Pt(6)
    p.paragraph_format.space_after = Pt(6)
    run = p.add_run(text)
    set_font(run, 14, True)
    preview.append(text)
    return p


def main():
    doc = Document()
    sec = doc.sections[0]
    sec.top_margin = Cm(2)
    sec.bottom_margin = Cm(2)
    sec.left_margin = Cm(3)
    sec.right_margin = Cm(1.5)

    style = doc.styles["Normal"]
    style.font.name = "Times New Roman"
    style._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    style.font.size = Pt(14)

    preview = []

    title_lines = [
        "Министерство цифрового развития, связи и массовых коммуникаций Российской Федерации",
        "Ордена Трудового Красного Знамени федеральное государственное бюджетное образовательное учреждение высшего образования",
        "«Московский технический университет связи и информатики»",
        "(МТУСИ)",
        "",
        "",
        "ОТЧЁТ",
        "о прохождении преддипломной практики",
        "по теме выпускной квалификационной работы",
        f"«{TITLE}»",
        "",
        "Студент: Провоторов Михаил Васильевич",
        "Группа: БВТ2201",
        "",
        "Москва, 2026",
    ]

    for line in title_lines:
        if line:
            add_paragraph(
                doc,
                line,
                preview,
                center=True,
                bold=line == "ОТЧЁТ",
                indent=False,
            )
        else:
            doc.add_paragraph()
            preview.append("")

    doc.add_page_break()

    add_heading(doc, "Индивидуальное задание по преддипломной практике", preview)
    assignment = [
        f"Проведение экспериментального исследования по теме выпускной квалификационной работы «{TITLE}».",
        "В ходе практики необходимо изучить существующие методы распознавания паспортных документов, подготовить обучающие и оценочные выборки, реализовать и исследовать несколько стратегий дообучения мультимодальной модели, разработать методы постобработки и парсинга MRZ, а также спроектировать архитектуру программной системы автоматического извлечения паспортных данных.",
        "Результаты практики должны быть использованы при подготовке аналитической, экспериментальной и проектной частей выпускной квалификационной работы.",
    ]
    for paragraph in assignment:
        add_paragraph(doc, paragraph, preview)

    for heading, paragraphs in SECTIONS:
        add_heading(doc, heading, preview)
        for paragraph in paragraphs:
            add_paragraph(doc, paragraph, preview)

    add_heading(doc, "Приложение А. Основные результаты и артефакты, подготовленные в ходе практики", preview)
    for paragraph in APPENDIX:
        add_paragraph(doc, paragraph, preview)

    OUT_TXT.write_text("\n\n".join(preview), encoding="utf-8")
    doc.save(OUT_DOCX)
    print(OUT_DOCX)
    print(OUT_TXT)
    print("OK")


if __name__ == "__main__":
    main()
